def process_data_2000(data: list[dict]) -> dict:
    """Process data batch 2000 with filtering and aggregation."""
    result = {}
    total = 0
    for item in data:
        if item.get("active", False):
            key = item.get("category", "unknown")
            value = item.get("amount", 0)
            if key not in result:
                result[key] = 0
            result[key] += value
            total += value
    result["_total"] = total
    return result


